// closest_neighbor[i] stores the index of closest(i).

// Precalculating closest_neighbor
vector<int> find_closest(const vector<long long>& nums) {
    int n = nums.size();
    vector<int> closest_neighbor(n);

    for (int i = 0; i < n; ++i) {
        int best_y = -1;
        long long min_diff = -1; // Use -1 as sentinel for infinity/not set

        // Check adjacent neighbors (i-1 and i+1)
        vector<int> candidates;
        if (i > 0) {
            candidates.push_back(i - 1);
        }
        if (i < n - 1) {
            candidates.push_back(i + 1);
        }

        if (candidates.empty()) {
            // Should not happen given constraints (n >= 2)
            closest_neighbor[i] = i; 
            continue;
        }

        for (int y : candidates) {
            long long diff = abs(nums[i] - nums[y]);
            if (best_y == -1 || diff < min_diff || (diff == min_diff && y < best_y)) {
                min_diff = diff;
                best_y = y;
            }
        }
        closest_neighbor[i] = best_y;
    }
    return closest_neighbor;
}

