using namespace std;

/**
 * @brief Solves the minimum cost path problem.
 * 
 * @param nums Strictly increasing integer array.
 * @param queries Array of [l_i, r_i] queries.
 * @return std::vector<long long> Array of minimum costs for each query.
 */
vector<long long> solve(const vector<long long>& nums, const vector<vector<long long>>& queries) {
    int n = nums.size();

    // 1. Precompute closest(x) for all x
    vector<int> closest(n);
    for (int x = 0; x < n; ++x) {
        long long min_diff = -1;
        int best_y = -1;

        // Check neighbors: y = x-1 and y = x+1

        // Candidate 1: y = x-1 (if x > 0)
        if (x > 0) {
            long long diff = abs(nums[x] - nums[x-1]);
            if (best_y == -1 || diff < min_diff || (diff == min_diff && (x-1) < best_y)) {
                min_diff = diff;
                best_y = x - 1;
            }
        }

        // Candidate 2: y = x+1 (if x < n-1)
        if (x < n - 1) {
            long long diff = abs(nums[x] - nums[x+1]);
            // The rule: If diff is smaller, choose it. If equal, choose smaller index.
            if (best_y == -1 || diff < min_diff || (diff == min_diff && (x+1) < best_y)) {
                min_diff = diff;
                best_y = x + 1;
            }
        }

