        // If both x-1 and x+1 are neighbors:
        // abs(nums[x] - nums[x-1]) vs abs(nums[x] - nums[x+1])
        // Since nums is strictly increasing:
        // abs(nums[x] - nums[x-1]) = nums[x] - nums[x-1]
        // abs(nums[x] - nums[x+1]) = nums[x+1] - nums[x]
        // The tie-breaker is choosing the smaller index (x-1 if equal).

        // Let's re-evaluate based on the strict definition: 
        // "If two adjacent indices have the same difference, choose the smaller index."

        long long diff_minus = -1;
        if (x > 0) {
            diff_minus = abs(nums[x] - nums[x-1]);
        }

        long long diff_plus = -1;
        if (x < n - 1) {
            diff_plus = abs(nums[x] - nums[x+1]);
        }

        if (x == 0) {
            // Only neighbor is x+1
            closest[x] = x + 1;
        } else if (x == n - 1) {
            // Only neighbor is x-1
            closest[x] = x - 1;
        } else {
            // Both neighbors exist
            if (diff_minus < diff_plus) {
                closest[x] = x - 1;
            } else if (diff_plus < diff_minus) {
                closest[x] = x + 1;
            } else {
                // Differences are equal, choose smaller index (x-1)
                closest[x] = x - 1;
            }
        }
