using System;
using System.Collections.Generic;
using System.Linq;

public class Solution {
    // Simple implementation of a Min-Heap for (Cost, NodeIndex)
    public class MinHeap
    {
        private List<(long Cost, int Index)> heap = new List<(long Cost, int Index)>();

        public int Count => heap.Count;

        public void Push(long cost, int index)
        {
            heap.Add((cost, index));
            BubbleUp(heap.Count - 1);
        }

        public (long Cost, int Index) Pop()
        {
            if (Count == 0) throw new InvalidOperationException("Heap is empty");
            var min = heap[0];
            int lastIndex = heap.Count - 1;
            heap[0] = heap[lastIndex];
            heap.RemoveAt(lastIndex);
            BubbleDown(0);
            return min;
        }

        private void BubbleUp(int index)
        {
            while (index > 0)
            {
                int parentIndex = (index - 1) / 2;
                if (heap[index].Cost < heap[parentIndex].Cost)
                {
                    Swap(index, parentIndex);
                    index = parentIndex;
                }
                else
                {
                    break;
                }
            }
        }

        private void BubbleDown(int index)
        {
            int smallest = index;
            int left = 2 * index + 1;
            int right = 2 * index + 2;

            if (left < heap.Count && heap[left].Cost < heap[smallest].Cost)
            {
                smallest = left;
            }
            if (right < heap.Count && heap[right].Cost < heap[smallest].Cost)
            {
                smallest = right;
            }

            if (smallest != index)
            {
                Swap(index, smallest);
                BubbleDown(smallest);
            }
        }

        private void Swap(int i, int j)
        {
            var temp = heap[i];
            heap[i] = heap[j];
            heap[j] = temp;
        }
    }

    public Array<Int64> solve(Array<Int64> nums, Array<Array<Int64>> queries) {
        int n = nums.Length;
        int[] closest = new int[n];

        // Step 1: Find closest(x) for all x
        for (int x = 0; x < n; x++) {
            int best_y = -1;
            long min_diff = long.MaxValue;

            int[] candidates = { x - 1, x + 1 };

            foreach (int y in candidates) {
                if (y >= 0 && y < n) {
                    long diff = Math.Abs(nums[x] - nums[y]);
                    if (diff < min_diff) {
                        min_diff = diff;
                        best_y = y;
                    } else if (diff == min_diff) {
                        // If differences are equal, choose the smaller index
                        if (y < best_y || best_y == -1) {
                            best_y = y;
                        }
                    }
                }
            }
            closest[x] = best_y;
        }

        Array<Int64> results = new Array<Int64>();

        foreach (var query in queries) {
            int L = (int)query[0];
            int R = (int)query[1];

            if (L == R) {
                results = results.Concat(new Array<Int64>() { 0 }).ToArray();
                continue;
            }

            // Dijkstra's Algorithm from L
            Array<Int64> dist = new Array<Int64>(n);
            for (int i = 0; i < n; i++) {
                dist[i] = long.MaxValue;
            }
            dist[L] = 0;

            MinHeap pq = new MinHeap();
            pq.Push(0, L);

            while (pq.Count > 0) {
                var (d_u, u) = pq.Pop();

                if (d_u > dist[u]) continue;

                // Optimization: If we found R, we can stop, as Dijkstra guarantees this is the shortest path.
                if (u == R) break;

                // 1. Move B: u -> closest(u), cost 1
                int c_u = closest[u];
                if (c_u != -1) {
                    long new_dist = dist[u] + 1;
                    if (new_dist < dist[c_u]) {
                        dist[c_u] = new_dist;
                        pq.Push(new_dist, c_u);
                    }
                }

                // 2. Move A: u -> j (any j), cost |nums[u] - nums[j]|
                // This step is O(N) per node processed, leading to O(N^2 log N) overall worst case.
                for (int j = 0; j < n; j++) {
                    if (u == j) continue;

                    long move_cost = Math.Abs(nums[u] - nums[j]);
                    long new_dist = dist[u] + move_cost;

                    if (new_dist < dist[j]) {
                        dist[j] = new_dist;
                        pq.Push(new_dist, j);
                    }
                }
            }

            results = results.Concat(new Array<Int64>() { dist[R] }).ToArray();
        }

        return results;
    }
}
